sys_security_acl.script:
if (gs.hasRole('x_2097092_linq.platform_admin')) {
  answer = true;
} else if (gs.hasRole('x_2097092_linq.college_admin')) {
  // College admin reads only their own college
  var userCollege = gs.getUser().getRecord().getValue('u_college');
  answer = (current.getUniqueValue() == userCollege);
} else {
  // Students can read active/verified colleges
  answer = (current.getValue('active') == 'true');
}
